func TestArchitectSplit_SpawnsEditorLoop(t *testing.T) {
	handler := agenticloop.NewMessageHandler(createTestConfig())

	// Create architect loop
	ctx := context.Background()
	taskResult, err := handler.HandleTask(ctx, agenticloop.TaskMessage{
		TaskID: "task-001",
		Role:   "architect",
		Model:  "qwen-32b",
		Prompt: "Design a distributed caching system",
	})
	if err != nil {
		t.Fatalf("HandleTask() error = %v", err)
	}

	architectLoopID := taskResult.LoopID

	// Architect completes
	response := agentic.AgentResponse{
		RequestID: "req-001",
		Status:    "complete",
		Message: agentic.ChatMessage{
			Role:    "assistant",
			Content: "Architecture design: Use Redis cluster with consistent hashing...",
		},
	}

	result, err := handler.HandleModelResponse(ctx, architectLoopID, response)
	if err != nil {
		t.Fatalf("HandleModelResponse() error = %v", err)
	}

	// Should spawn editor loop
	if result.EditorLoopID == "" {
		t.Fatal("Architect completion should spawn editor loop")
	}

	// Editor loop ID should be different
	if result.EditorLoopID == architectLoopID {
		t.Error("Editor loop ID should differ from architect loop ID")
	}

	// Verify editor loop was created with correct properties
	editorEntity, err := handler.GetLoop(result.EditorLoopID)
	if err != nil {
		t.Fatalf("GetLoop() for editor error = %v", err)
	}

	if editorEntity.Role != "editor" {
		t.Errorf("Editor entity role = %s, want editor", editorEntity.Role)
	}

	if editorEntity.TaskID != "task-001" {
		t.Errorf("Editor entity task ID = %s, want task-001 (same as architect)", editorEntity.TaskID)
	}

	if editorEntity.Model == "" {
		t.Error("Editor entity should have a model assigned")
	}

	if editorEntity.State != agentic.LoopStateExploring {
		t.Errorf("Editor initial state = %s, want exploring", editorEntity.State)
	}
}

