func TestArchitectSplit_SameTaskID(t *testing.T) {
	handler := agenticloop.NewMessageHandler(createTestConfig())

	taskID := "task-shared-001"

	ctx := context.Background()
	architectTask, err := handler.HandleTask(ctx, agenticloop.TaskMessage{
		TaskID: taskID,
		Role:   "architect",
		Model:  "qwen-32b",
		Prompt: "Design system",
	})
	if err != nil {
		t.Fatalf("HandleTask() error = %v", err)
	}

	architectResult, err := handler.HandleModelResponse(ctx, architectTask.LoopID, agentic.AgentResponse{
		RequestID: "req-001",
		Status:    "complete",
		Message: agentic.ChatMessage{
			Role:    "assistant",
			Content: "Architecture complete",
		},
	})
	if err != nil {
		t.Fatalf("HandleModelResponse() error = %v", err)
	}

	editorLoopID := architectResult.EditorLoopID
	if editorLoopID == "" {
		t.Fatal("Editor loop should be spawned")
	}

	// Verify editor has same task ID
	editorEntity, err := handler.GetLoop(editorLoopID)
	if err != nil {
		t.Fatalf("GetLoop() for editor error = %v", err)
	}

	if editorEntity.TaskID != taskID {
		t.Errorf("Editor task ID = %s, want %s (same as architect)", editorEntity.TaskID, taskID)
	}

	// Verify architect has same task ID
	architectEntity, err := handler.GetLoop(architectTask.LoopID)
	if err != nil {
		t.Fatalf("GetLoop() for architect error = %v", err)
	}

	if architectEntity.TaskID != taskID {
		t.Errorf("Architect task ID = %s, want %s", architectEntity.TaskID, taskID)
	}

	// Both should share task ID but have different loop IDs
	if architectEntity.TaskID != editorEntity.TaskID {
		t.Error("Architect and editor should share the same task ID")
	}

	if architectEntity.ID == editorEntity.ID {
		t.Error("Architect and editor should have different loop IDs")
	}
}

