func TestArchitectSplit_ArchitectFailureDoesNotSpawnEditor(t *testing.T) {
	handler := agenticloop.NewMessageHandler(createTestConfig())

	ctx := context.Background()
	architectTask, err := handler.HandleTask(ctx, agenticloop.TaskMessage{
		TaskID: "task-001",
		Role:   "architect",
		Model:  "qwen-32b",
		Prompt: "Design system",
	})
	if err != nil {
		t.Fatalf("HandleTask() error = %v", err)
	}

	// Architect fails
	response := agentic.AgentResponse{
		RequestID: "req-001",
		Status:    "error",
		Error:     "Model timeout",
	}

	result, err := handler.HandleModelResponse(ctx, architectTask.LoopID, response)
	if err != nil {
		t.Fatalf("HandleModelResponse() error = %v", err)
	}

	// Should NOT spawn editor on error
	if result.EditorLoopID != "" {
		t.Error("Editor should not be spawned when architect fails")
	}

	// Architect should be marked as failed or retrying
	if result.State != agentic.LoopStateFailed && result.RetryScheduled == false {
		t.Error("Architect should be marked as failed or scheduled for retry")
	}
}
